function switchTab(t){
  document.querySelectorAll('.a-tab').forEach((el,i)=>el.classList.toggle('on',(t==='login'&&i===0)||(t==='register'&&i===1)));
  document.getElementById('login-f').classList.toggle('on',t==='login');
  document.getElementById('reg-f').classList.toggle('on',t==='register');
}
function togglePw(id,btn){const el=document.getElementById(id);el.type=el.type==='password'?'text':'password';btn.textContent=el.type==='password'?'👁':'🙈';}
function setErr(id,msg){const el=document.getElementById(id);el.textContent=msg;el.classList.add('on');setTimeout(()=>el.classList.remove('on'),4500);}

function handleLogin(){
  const em=document.getElementById('l-email').value.trim();
  const pw=document.getElementById('l-pw').value;
  if(!em||!pw){setErr('l-err','Please enter email and password.');return;}
  // Admin detection
  if(_isAdmin(em,pw)){
    CU={email:em,name:'Administrator',isAdmin:true,isPremium:true};
    sessionStorage.setItem('gms_sess',JSON.stringify(CU));
    document.getElementById('auth-gate').style.display='none';
    launchAdmin();
    return;
  }
  // Regular user
  const u=DB.users.find(x=>x.email===em||x.contact===em);
  if(!u){setErr('l-err','No account found with that email.');return;}
  if(u.password!==pw){setErr('l-err','Incorrect password. Please try again.');return;}
  CU={...u};
  sessionStorage.setItem('gms_sess',JSON.stringify(CU));
  document.getElementById('auth-gate').style.display='none';
  boot();
}

function handleRegister(){
  const fn=document.getElementById('r-fn').value.trim();
  const ln=document.getElementById('r-ln').value.trim();
  const ct=document.getElementById('r-ct').value.trim();
  const cy=document.getElementById('r-country').value;
  const ag=parseInt(document.getElementById('r-age').value);
  const pw=document.getElementById('r-pw').value;
  const pw2=document.getElementById('r-pw2').value;
  if(!fn||!ln||!ct||!ag||!pw){setErr('r-err','Please fill in all fields.');return;}
  if(pw!==pw2){setErr('r-err','Passwords do not match.');return;}
  if(pw.length<6){setErr('r-err','Password must be at least 6 characters.');return;}
  if(ag<16){setErr('r-err','You must be at least 16 years old.');return;}
  const users=DB.users;
  if(users.find(x=>x.email===ct||x.contact===ct)){setErr('r-err','This email/phone is already registered.');return;}
  const nu={name:fn+' '+ln,email:ct,contact:ct,password:pw,country:cy,age:ag,ageGroup:ag<=30?'18-30':'30-50',isPremium:false,joined:new Date().toISOString().split('T')[0]};
  DB.users=[...users,nu];
  CU={...nu};
  sessionStorage.setItem('gms_sess',JSON.stringify(CU));
  document.getElementById('auth-gate').style.display='none';
  boot();
  toast('Account created! Welcome to GMS 🎉','ok');
}

function boot(){
  isPrem=CU.isPremium||false;
  const fn=(CU.name||'User').split(' ')[0];
  document.getElementById('nav-uname').textContent=fn;
  document.getElementById('h-wtext').textContent='👋 Welcome back, '+fn+'! Your GMS Pathway is ready.';
  document.getElementById('h-welcome').style.display='block';
  if(isPrem) document.getElementById('nav-premium').style.display='inline-flex';
  updateDash();
  document.getElementById('main-site').classList.add('on');
}

function logout(){
  sessionStorage.removeItem('gms_sess');CU=null;isPrem=false;
  document.getElementById('adm').classList.remove('on');
  document.getElementById('main-site').classList.remove('on');
  document.getElementById('auth-gate').style.display='flex';
  document.getElementById('l-email').value='';
  document.getElementById('l-pw').value='';
}

