// ADMIN — DASHBOARD
// ============================================================
function renderDash(){
  const users=DB.users,txns=DB.txns,tasks=DB.tasks,transfers=DB.transfers;
  const rev=txns.filter(t=>t.status==='completed').reduce((s,t)=>s+t.usd,0);
  const xOut=transfers.filter(t=>t.status==='completed').reduce((s,t)=>s+t.usd,0);
  const prem=users.filter(u=>u.isPremium).length;
  const active=tasks.filter(t=>t.col!=='done').length;
  document.getElementById('adm-stats').innerHTML=`
    <div class="astat"><div class="astat-v">${users.length}</div><div class="astat-l">Total Users</div></div>
    <div class="astat"><div class="astat-v">$${rev.toFixed(2)}</div><div class="astat-l">Total Revenue</div></div>
    <div class="astat"><div class="astat-v">$${Math.max(0,rev-xOut).toFixed(2)}</div><div class="astat-l">Wallet Balance</div></div>
    <div class="astat"><div class="astat-v">${prem}</div><div class="astat-l">Premium Users</div></div>`;
  let rp=txns.slice().reverse().slice(0,6).map(t=>`✅ <strong style="color:#fff">${t.user}</strong> — ${t.local} (${t.date})<br>`).join('');
  document.getElementById('adm-recent-pay').innerHTML=rp||'No payments yet.';
  const cc={ZM:0,KE:0,NG:0,ZA:0,TZ:0,GH:0,MW:0,ZW:0};
  const cn={ZM:'🇿🇲 Zambia',KE:'🇰🇪 Kenya',NG:'🇳🇬 Nigeria',ZA:'🇿🇦 S.Africa',TZ:'🇹🇿 Tanzania',GH:'🇬🇭 Ghana',MW:'🇲🇼 Malawi',ZW:'🇿🇼 Zimbabwe'};
  txns.filter(t=>t.status==='completed').forEach(t=>{if(cc[t.country]!==undefined)cc[t.country]+=t.usd;});
  document.getElementById('adm-ctry-rev').innerHTML=Object.entries(cc).map(([k,v])=>`<tr><td>${cn[k]||k}</td><td>${txns.filter(t=>t.country===k&&t.status==='completed').length}</td><td>$${v.toFixed(2)}</td></tr>`).join('');
}

// ============================================================
// ADMIN — USERS
// ============================================================
function renderUsers(){
  const q=(document.getElementById('u-search').value||'').toLowerCase();
  const fc=document.getElementById('u-fc').value;
  const fp=document.getElementById('u-fp').value;
  let users=DB.users;
  if(q) users=users.filter(u=>(u.name||'').toLowerCase().includes(q)||(u.email||'').toLowerCase().includes(q));
  if(fc) users=users.filter(u=>u.country===fc);
  if(fp!=='') users=users.filter(u=>String(u.isPremium)===fp);
  const total=users.length,pages=Math.max(1,Math.ceil(total/PG));
  if(uPage>=pages) uPage=pages-1;
  const sl=users.slice(uPage*PG,(uPage+1)*PG);
  document.getElementById('u-tbody').innerHTML=sl.map((u,i)=>`
    <tr>
      <td>${uPage*PG+i+1}</td>
      <td><strong>${u.name}</strong></td>
      <td style="font-size:.75rem">${u.email||u.contact}</td>
      <td>${u.country}</td><td>${u.age||'—'}</td>
      <td>${u.isPremium?'<span class="bdg by">⭐ Premium</span>':'<span class="bdg bgr">Free</span>'}</td>
      <td style="font-size:.75rem">${u.joined||'—'}</td>
      <td><button class="del-btn" onclick="delUser('${u.email||u.contact}')">🗑</button></td>
    </tr>`).join('');
  let pg=`<span style="color:rgba(255,255,255,.4);font-size:.8rem;margin-right:.4rem;">${total} users</span>`;
  for(let i=0;i<pages;i++) pg+=`<button class="abtn ${i===uPage?'abtn-g':'abtn-gh'}" onclick="uPage=${i};renderUsers()" style="min-width:34px;padding:.38rem .6rem;">${i+1}</button>`;
  document.getElementById('u-pages').innerHTML=pg;
}
function delUser(id){if(!confirm('Delete this user permanently?'))return;DB.users=DB.users.filter(u=>u.email!==id&&u.contact!==id);renderUsers();renderDash();toast('User deleted','err');}

// ============================================================
// ADMIN — WALLET
// ============================================================
function renderWallet(){
  const rev=DB.txns.filter(t=>t.status==='completed').reduce((s,t)=>s+t.usd,0);
  const xOut=DB.transfers.filter(t=>t.status==='completed').reduce((s,t)=>s+t.usd,0);
  const bal=Math.max(0,rev-xOut);
  document.getElementById('w-balance').textContent='$'+bal.toFixed(2);
  document.getElementById('w-sub').textContent=`From ${DB.txns.filter(t=>t.status==='completed').length} completed payments · $${xOut.toFixed(2)} transferred out`;
  convertCurrency();
  buildFxTable();
  // History: combine txns + transfers
  const hist=[...DB.txns.map(t=>({date:t.date,type:'💰 Payment In',who:t.user,amt:'$'+t.usd.toFixed(2),cur:t.localCur||'USD',status:t.status})),...DB.transfers.map(t=>({date:t.date,type:'💸 Transfer Out',who:t.to,amt:'-$'+t.usd.toFixed(2),cur:t.localCur||'USD',status:t.status}))].sort((a,b)=>b.date.localeCompare(a.date)).slice(0,10);
  const sc={completed:'bg',pending:'by',failed:'br'};
  document.getElementById('w-history').innerHTML=hist.length===0?'<tr><td colspan="6" style="text-align:center;color:rgba(255,255,255,.35);">No history yet</td></tr>':hist.map(h=>`<tr><td style="font-size:.75rem">${h.date}</td><td>${h.type}</td><td>${h.who}</td><td>${h.amt}</td><td>${h.cur}</td><td><span class="bdg ${sc[h.status]||'bgr'}">${h.status}</span></td></tr>`).join('');
}

function convertCurrency(){
  const amt=parseFloat(document.getElementById('fx-amt').value)||0;
  const from=document.getElementById('fx-from').value;
  const to=document.getElementById('fx-to').value;
  const result=fx(amt,from,to);
  document.getElementById('fx-result').textContent=fmtFx(result,to)+' '+to;
  document.getElementById('fx-rate-info').textContent=`1 ${from} = ${(FX[to]/FX[from]).toFixed(4)} ${to} · Rates: April 2026`;
}

function buildFxTable(){
  const el=document.getElementById('fx-rates-table');
  if(!el) return;
  el.innerHTML=Object.entries(FX).map(([k,v])=>`<tr><td>${FX_SYM[k]} ${k}</td><td>${v.toFixed(4)}</td><td>${fmtFx(7.65*v,k)}</td></tr>`).join('');
}

// ============================================================
// ADMIN — TRANSACTIONS
// ============================================================
function renderTx(){
  const q=(document.getElementById('tx-q').value||'').toLowerCase();
  const fs=document.getElementById('tx-fs').value;
  let txs=DB.txns;
  if(q) txs=txs.filter(t=>(t.user||'').toLowerCase().includes(q)||(t.ref||'').toLowerCase().includes(q));
  if(fs) txs=txs.filter(t=>t.status===fs);
  const comp=txs.filter(t=>t.status==='completed');
  document.getElementById('tx-total').textContent='$'+comp.reduce((s,t)=>s+t.usd,0).toFixed(2);
  document.getElementById('tx-count').textContent=txs.length;
  const today=new Date().toISOString().split('T')[0];
  document.getElementById('tx-today').textContent=txs.filter(t=>t.date===today).length;
  const sc={completed:'bg',pending:'by',failed:'br'};
  document.getElementById('tx-tbody').innerHTML=txs.slice().reverse().map(t=>`<tr><td style="font-size:.73rem">${t.ref}</td><td>${t.user}</td><td>${t.country}</td><td>${t.local}</td><td>$${t.usd.toFixed(2)}</td><td style="font-size:.74rem">${t.provider||'—'}</td><td><span class="bdg ${sc[t.status]||'bgr'}">${t.status}</span></td><td style="font-size:.73rem">${t.date}</td></tr>`).join('');
}
function exportTx(){exportCSV(DB.txns.map(t=>[t.ref,t.user,t.country,t.local,t.usd,t.provider||'',t.status,t.date]),['Ref','User','Country','Local Amt','USD','Provider','Status','Date'],'gms_transactions.csv');}

