// ADMIN — TRANSFER
// ============================================================
function renderTransfer(){
  const rev=DB.txns.filter(t=>t.status==='completed').reduce((s,t)=>s+t.usd,0);
  const xOut=DB.transfers.filter(t=>t.status==='completed').reduce((s,t)=>s+t.usd,0);
  const bal=Math.max(0,rev-xOut);
  document.getElementById('tf-bal').textContent='$'+bal.toFixed(2);
  document.getElementById('tf-bal-sub').textContent=`Total collected: $${rev.toFixed(2)} · Already transferred: $${xOut.toFixed(2)}`;
  renderTfTable();
  previewTransfer();
}
function previewTransfer(){
  const amt=parseFloat(document.getElementById('tf-amt').value)||0;
  const cur=document.getElementById('tf-cur').value;
  if(!amt){document.getElementById('tf-preview').innerHTML='<span style="color:rgba(255,255,255,.38);font-size:.83rem;">Enter amount to preview conversion</span>';return;}
  const converted=fx(amt,'USD',cur);
  document.getElementById('tf-preview').innerHTML=`<div style="display:flex;align-items:center;gap:1rem;flex-wrap:wrap;"><span style="color:rgba(255,255,255,.55);font-size:.82rem;">$${amt.toFixed(2)} USD =</span><span style="color:var(--gold2);font-size:1.3rem;font-weight:700;">${fmtFx(converted,cur)} ${cur}</span><span style="color:rgba(255,255,255,.38);font-size:.78rem;">Rate: 1 USD = ${FX[cur].toFixed(4)} ${cur}</span></div>`;
}
function doTransfer(){
  const name=document.getElementById('tf-name').value.trim();
  const acct=document.getElementById('tf-acct').value.trim();
  const amt=parseFloat(document.getElementById('tf-amt').value);
  const cur=document.getElementById('tf-cur').value;
  const net=document.getElementById('tf-net').value;
  const note=document.getElementById('tf-note').value.trim();
  if(!name||!acct||!amt){toast('Fill in all required fields','err');return;}
  if(isNaN(amt)||amt<=0){toast('Enter a valid amount','err');return;}
  const rev=DB.txns.filter(t=>t.status==='completed').reduce((s,t)=>s+t.usd,0);
  const xOut=DB.transfers.filter(t=>t.status==='completed').reduce((s,t)=>s+t.usd,0);
  const bal=Math.max(0,rev-xOut);
  if(amt>bal){toast('Insufficient balance! Available: $'+bal.toFixed(2),'err');return;}
  const converted=fx(amt,'USD',cur);
  const ref='TF-'+Date.now().toString().slice(-7);
  DB.transfers=[...DB.transfers,{ref,to:name,account:acct,network:net,usd:amt,localAmt:fmtFx(converted,cur),localCur:cur,status:'completed',date:new Date().toISOString().split('T')[0],note}];
  clearTf();renderTransfer();
  toast(`✅ Sent ${fmtFx(converted,cur)} ${cur} to ${name} — Ref: ${ref}`,'ok');
}
function renderTfTable(){
  const tfs=DB.transfers;
  document.getElementById('tf-tbody').innerHTML=tfs.length===0?'<tr><td colspan="8" style="text-align:center;color:rgba(255,255,255,.33);padding:1rem;">No transfers yet</td></tr>':tfs.slice().reverse().map(t=>`<tr><td style="font-size:.73rem">${t.ref}</td><td>${t.to}</td><td style="font-size:.74rem">${t.account}</td><td style="font-size:.74rem">${t.network}</td><td>$${t.usd.toFixed(2)}</td><td style="font-size:.78rem">${t.localAmt||'—'} ${t.localCur||''}</td><td><span class="bdg bg">${t.status}</span></td><td style="font-size:.73rem">${t.date}</td></tr>`).join('');
}
function clearTf(){['tf-name','tf-acct','tf-amt','tf-note'].forEach(id=>{const el=document.getElementById(id);if(el)el.value='';});document.getElementById('tf-preview').innerHTML='<span style="color:rgba(255,255,255,.38);font-size:.83rem;">Enter amount to preview conversion</span>';}

