function renderTickets(){
  const fs=document.getElementById('tk-fs').value;
  let tks=DB.tickets;
  if(fs) tks=tks.filter(t=>t.status===fs);
  const sc={open:'br','in-progress':'by',resolved:'bg'};
  document.getElementById('tk-list').innerHTML=tks.length===0?'<div style="color:rgba(255,255,255,.35);text-align:center;padding:2rem;">No tickets</div>':
    tks.slice().reverse().map(t=>`<div class="acard" style="margin-bottom:.7rem;">
      <div style="display:flex;justify-content:space-between;align-items:start;flex-wrap:wrap;gap:.5rem;">
        <div><strong style="color:#fff">${t.subject}</strong><div style="color:rgba(255,255,255,.42);font-size:.79rem;margin-top:.15rem;">${t.user} · ${t.email} · ${t.date}</div></div>
        <div style="display:flex;gap:.4rem;flex-wrap:wrap;align-items:center;">
          <span class="bdg ${sc[t.status]||'bgr'}">${t.status}</span>
          ${t.status!=='resolved'?`<button class="abtn abtn-g" style="font-size:.72rem;padding:.28rem .65rem;" onclick="resolveTicket(${t.id})">✓ Resolve</button>`:''}
          <button class="abtn abtn-r" style="font-size:.72rem;padding:.28rem .65rem;" onclick="delTicket(${t.id})">🗑</button>
        </div>
      </div>
      ${t.msg?`<div style="color:rgba(255,255,255,.52);font-size:.81rem;margin-top:.55rem;padding:.55rem;background:rgba(255,255,255,.04);border-radius:8px;">${t.msg}</div>`:''}
      <div style="margin-top:.7rem;display:flex;gap:.5rem;align-items:center;">
        <input class="ainp" id="rp-${t.id}" placeholder="Type reply..." style="flex:1;">
        <button class="abtn abtn-g" onclick="sendReply(${t.id})" style="font-size:.78rem;">📧 Reply</button>
      </div>
    </div>`).join('');
}
function resolveTicket(id){const ts=DB.tickets;const i=ts.findIndex(t=>t.id===id);if(i>-1){ts[i].status='resolved';DB.tickets=ts;}renderTickets();toast('Ticket resolved ✓','ok');}
function delTicket(id){DB.tickets=DB.tickets.filter(t=>t.id!==id);renderTickets();toast('Ticket deleted','err');}
function sendReply(id){const v=document.getElementById('rp-'+id).value.trim();if(!v){toast('Enter a reply','err');return;}toast('📧 Reply sent to user!','ok');resolveTicket(id);}
function addTicket(){const s=prompt('Ticket subject:');if(!s)return;DB.tickets=[...DB.tickets,{id:Date.now(),user:'Manual',email:'admin',subject:s,status:'open',date:new Date().toISOString().split('T')[0],msg:''}];renderTickets();toast('Ticket created','ok');}

