function addICPost(){const title=document.getElementById('ic-title').value.trim();const body=document.getElementById('ic-body').value.trim();const platform=document.getElementById('ic-platform').value;const status=document.getElementById('ic-status').value;if(!title){toast('Enter a title','err');return;}DeptDB.icPosts=[...DeptDB.icPosts,{title,body,platform,status,date:new Date().toISOString().split('T')[0]}];renderDepts();toast('Post created ✓','ok');}
function delICPost(i){const p=DeptDB.icPosts;p.splice(i,1);DeptDB.icPosts=p;renderDepts();}
