function schedPost(){const pl=document.getElementById('p-plat').value;const ti=document.getElementById('p-time').value;const tx=document.getElementById('p-txt').value.trim();if(!tx||!ti){toast('Fill content and time','err');return;}DB.posts=[...DB.posts,{platform:pl,time:ti,content:tx}];document.getElementById('p-txt').value='';renderSocial();toast('Post scheduled ✓','ok');}
