// ADMIN — KANBAN
// ============================================================
function renderKanban(){
  const tasks=DB.tasks;
  const cols=[{k:'todo',l:'To Do',c:'#ef4444'},{k:'progress',l:'In Progress',c:'var(--gold)'},{k:'done',l:'Done',c:'#4ade80'}];
  const pm={high:'🔴',med:'🟡',low:'🟢'};
  document.getElementById('kboard').innerHTML=cols.map(col=>{
    const items=tasks.filter(t=>t.col===col.k);
    return `<div class="kcol"><div class="kcol-title" style="color:${col.c}">${col.l}<span class="kcol-cnt">${items.length}</span></div>${items.map(t=>`<div class="ktask" onclick="moveTask(${t.id})"><div class="kt-title">${pm[t.priority]||'⚪'} ${t.title}</div><div class="kt-meta">${t.date||''} · <span style="color:#fca5a5;cursor:pointer;" onclick="event.stopPropagation();delTask(${t.id})">🗑 del</span></div></div>`).join('')}</div>`;
  }).join('');
}
function addTask(){const ti=document.getElementById('t-inp').value.trim();const col=document.getElementById('t-col').value;const pri=document.getElementById('t-pri').value;if(!ti){toast('Enter task title','err');return;}const ts=DB.tasks;ts.push({id:Date.now(),title:ti,col,priority:pri,date:new Date().toISOString().split('T')[0]});DB.tasks=ts;document.getElementById('t-inp').value='';renderKanban();toast('Task added ✓','ok');}
function moveTask(id){const ts=DB.tasks;const t=ts.find(x=>x.id===id);if(!t)return;const o=['todo','progress','done'];t.col=o[(o.indexOf(t.col)+1)%3];DB.tasks=ts;renderKanban();toast('Task moved ✓','ok');}
function delTask(id){DB.tasks=DB.tasks.filter(t=>t.id!==id);renderKanban();}

