function openTopic(key){
  const d=TPC[key];if(!d)return;
  const hd=document.getElementById('tm-hd');
  hd.className='tm-hd'+(d.hc?' '+d.hc:'');
  document.getElementById('tm-icon').textContent=d.icon;
  document.getElementById('tm-title').textContent=d.title;
  document.getElementById('tm-sub').textContent=d.sub;
  document.getElementById('tm-act').textContent=d.act||'Mark Complete ✓';
  document.getElementById('tm-act').onclick=()=>completeTopic(key);
  let html='';
  d.secs.forEach(s=>{
    html+=`<div class="tsec"><h4>${s.h}</h4>`;
    if(s.p) html+=`<p>${s.p}</p>`;
    if(s.l){html+='<ul>';s.l.forEach(li=>html+=`<li>${li}</li>`);html+='</ul>';}
    if(s.tip){const gc=s.tip.type==='g'?' gld-tip':'';html+=`<div class="tip${gc}"><p><strong>${s.tip.l}:</strong> ${s.tip.t}</p></div>`;}
    html+='</div>';
  });
  document.getElementById('tm-body').innerHTML=html;
  document.getElementById('topic-ov').classList.add('on');
  document.body.style.overflow='hidden';
}
function gatedTopic(key){
  if(!isPrem){
    toast('🔒 This content requires The Vault — unlock for $7.65','');
    setTimeout(openPay,1600);return;
  }
  openTopic(key);
}
function completeTopic(key){
  const free=['budgeting','saving','debt','scams'];
  if(free.includes(key)){growPct=Math.min(growPct+15,100);updateDash();toast('✅ Lesson complete! Grow progress: '+growPct+'%','ok');}
  else toast('✅ Saved to your learning plan!','ok');
  closeTopic();
}
function closeTopic(){document.getElementById('topic-ov').classList.remove('on');document.body.style.overflow='';}

