function toast(msg,type){const el=document.getElementById('toast-el');el.textContent=msg;el.className='toast on '+(type||'');clearTimeout(window._tt);window._tt=setTimeout(()=>el.classList.remove('on'),3800);}
function ss(sel){const el=document.querySelector(sel);if(el)el.scrollIntoView({behavior:'smooth',block:'start'});}
function exportCSV(rows,headers,filename){const c=[headers,...rows].map(r=>r.map(v=>'"'+(String(v||'').replace(/"/g,'""'))+'"').join(',')).join('\n');const a=document.createElement('a');a.href=URL.createObjectURL(new Blob([c],{type:'text/csv'}));a.download=filename;a.click();toast('CSV exported ✓','ok');}
document.getElementById('topic-ov').addEventListener('click',function(e){if(e.target===this)closeTopic();});

