function openFeedback(){document.getElementById('feedback-page').classList.add('on');document.body.style.overflow='hidden';}
function closeFeedback(){document.getElementById('feedback-page').classList.remove('on');document.body.style.overflow='';}
function switchFbTab(tab){
  document.querySelectorAll('.fb-tab').forEach((el,i)=>el.classList.toggle('on',(tab==='feedback'&&i===0)||(tab==='mentor'&&i===1)));
  document.getElementById('fbf-feedback').classList.toggle('on',tab==='feedback');
  document.getElementById('fbf-mentor').classList.toggle('on',tab==='mentor');
}
function submitFeedback(){
  const name=document.getElementById('fb-name').value.trim();
  const email=document.getElementById('fb-email').value.trim();
  const msg=document.getElementById('fb-msg').value.trim();
  if(!name||!email||!msg){document.getElementById('fb-err').textContent='Please fill in all fields.';document.getElementById('fb-err').classList.add('on');return;}
  document.getElementById('fb-err').classList.remove('on');
  // Save ticket
  DB.tickets=[...DB.tickets,{id:Date.now(),user:name,email:email,subject:'User Feedback',status:'open',date:new Date().toISOString().split('T')[0],msg:msg}];
  document.getElementById('fb-suc').textContent='✅ Thank you! Your feedback has been received. We read every message.';
  document.getElementById('fb-suc').classList.add('on');
  document.getElementById('fb-name').value='';document.getElementById('fb-email').value='';document.getElementById('fb-msg').value='';
  setTimeout(()=>document.getElementById('fb-suc').classList.remove('on'),5000);
}
function submitMentor(){
  const name=document.getElementById('mt-name').value.trim();
  const email=document.getElementById('mt-email').value.trim();
  const country=document.getElementById('mt-country').value;
  const topic=document.getElementById('mt-topic').value;
  const msg=document.getElementById('mt-msg').value.trim();
  if(!name||!email||!msg){document.getElementById('mt-err').textContent='Please fill in all fields.';document.getElementById('mt-err').classList.add('on');return;}
  document.getElementById('mt-err').classList.remove('on');
  DB.tickets=[...DB.tickets,{id:Date.now(),user:name,email:email,subject:'Mentorship Request: '+topic,status:'open',date:new Date().toISOString().split('T')[0],msg:'Country: '+country+' | Topic: '+topic+' | '+msg}];
  document.getElementById('mt-suc').textContent='🎓 Mentorship request received! A GMS mentor will contact you at '+email+' within 24–48 hours.';
  document.getElementById('mt-suc').classList.add('on');
  ['mt-name','mt-email','mt-msg'].forEach(id=>document.getElementById(id).value='');
  setTimeout(()=>document.getElementById('mt-suc').classList.remove('on'),7000);
}

// ============================================================
// PHASE DASHBOARDS
// ============================================================
function openPhase(phase){
  document.getElementById('phase-'+phase).classList.add('on');
  document.body.style.overflow='hidden';
  // populate topic lists
  if(phase==='multiply') renderPhaseTopics('ph-mul-topics', ['investing','sidehustles','mobilemoney','localproducts']);
  if(phase==='succeed')  renderPhaseTopics('ph-suc-topics', ['retirement','assetprotection','generational']);
  if(phase==='legacy')   renderPhaseTopics('ph-leg-topics', ['generational','retirement','assetprotection']);
  // show/hide lock CTAs based on premium
  ['mul','suc','leg'].forEach(p=>{
    const cta=document.getElementById('ph-'+p+'-lock-cta');
    if(cta) cta.style.display = isPrem ? 'none' : 'block';
    const btn=document.getElementById('ph-'+p+'-btn');
    if(btn&&isPrem) btn.textContent='✅ You Have Full Access';
  });
}
function closePhase(phase){
  document.getElementById('phase-'+phase).classList.remove('on');
  document.body.style.overflow='';
}
function renderPhaseTopics(containerId, keys){
  const el=document.getElementById(containerId);
  if(!el) return;
  el.innerHTML='<div class="ph-topics">'+keys.map(k=>{
    const d=TPC[k];if(!d)return'';
    const locked=!isPrem&&d.hc;
    return `<button class="ph-topic-btn" onclick="${locked?'openPay()':'openTopic(\''+k+'\')'}">
      <div class="ph-topic-icon">${d.icon}</div>
      <div class="ph-topic-name">${locked?'🔐 ':''} ${d.title}</div>
      <div class="ph-topic-time">${d.sub}</div>
    </button>`;
  }).join('')+'</div>';
}

