function openLeader(idx){
  const d = LEADER_DATA[idx];
  if(!d) return;
  // Build visual hero
  document.getElementById('lm-img-inner').innerHTML = `
    <div style="width:100%;height:100%;background:${d.bg};display:flex;flex-direction:column;align-items:center;justify-content:center;position:relative;">
      <div style="position:absolute;top:0;left:0;right:0;height:3px;background:linear-gradient(90deg,var(--gold),var(--gold2),var(--gold));"></div>
      <div style="position:absolute;top:1rem;right:1.2rem;background:${d.badgeColor};border:1px solid ${d.badgeTextColor}44;color:${d.badgeTextColor};font-size:.65rem;font-weight:700;padding:.22rem .65rem;border-radius:50px;letter-spacing:.06em;">${d.badge}</div>
      <div style="width:120px;height:120px;border-radius:50%;background:rgba(0,0,0,.3);border:3px solid rgba(255,255,255,.25);display:flex;align-items:center;justify-content:center;font-size:4rem;box-shadow:0 8px 32px rgba(0,0,0,.5);">${d.icon}</div>
    </div>`;
  document.getElementById('lm-name').textContent = d.name;
  document.getElementById('lm-title').textContent = d.title;
  document.getElementById('lm-quote').textContent = d.quote;
  document.getElementById('lm-bio').textContent = d.bio;
  document.getElementById('lm-lesson').textContent = d.lesson;
  document.getElementById('leader-modal').classList.add('on');
  document.body.style.overflow='hidden';
}
function closeLeader(){
  document.getElementById('leader-modal').classList.remove('on');
  document.body.style.overflow='';
}
document.getElementById('leader-modal').addEventListener('click',function(e){
  if(e.target===this) closeLeader();
});

// ============================================================
// LEADERS SWIPE — touch support + drag
// ============================================================
(function initLeaders(){
  const track = document.getElementById('leaders-track');
  if(!track) return;
  const wrap = track.closest('.leaders-track-wrap')||track.parentElement;
  if(!wrap) return;
  let curIdx=0, startX=0, isDragging=false, startScrollLeft=0;

  function getCardWidth(){ const card=track.querySelector('.leader-card'); return card ? card.offsetWidth+24 : 340; }
  function numCards(){ return track.querySelectorAll('.leader-card').length; }
  function updateDots(){
    const dots=document.querySelectorAll('.leader-dot');
    dots.forEach((d,i)=>d.classList.toggle('on',i===curIdx));
  }
  function scrollTo(idx){
    const n=numCards(); curIdx=Math.max(0,Math.min(idx,n-1));
    track.style.transform=`translateX(calc(-${curIdx * getCardWidth()}px + 0px))`;
    updateDots();
  }
  window.leadersScroll = function(dir){ scrollTo(curIdx+dir); };

  // Build dots
  const dotsWrap=document.getElementById('leaders-dots');
  if(dotsWrap){
    dotsWrap.innerHTML='';
    for(let i=0;i<8;i++){
      const d=document.createElement('div');
      d.className='leader-dot'+(i===0?' on':'');
      d.onclick=()=>scrollTo(i);
      dotsWrap.appendChild(d);
    }
  }

  // Mouse drag
  wrap.addEventListener('mousedown',e=>{isDragging=true;startX=e.pageX;startScrollLeft=curIdx*getCardWidth();wrap.style.cursor='grabbing';});
  window.addEventListener('mousemove',e=>{if(!isDragging)return;});
  window.addEventListener('mouseup',e=>{
    if(!isDragging)return;isDragging=false;wrap.style.cursor='grab';
    const diff=startX-e.pageX;
    if(Math.abs(diff)>60) scrollTo(diff>0?curIdx+1:curIdx-1);
  });

  // Touch swipe
  wrap.addEventListener('touchstart',e=>{startX=e.touches[0].clientX;},{passive:true});
  wrap.addEventListener('touchend',e=>{
    const diff=startX-e.changedTouches[0].clientX;
    if(Math.abs(diff)>50) scrollTo(diff>0?curIdx+1:curIdx-1);
  },{passive:true});

  // Auto scroll
  let autoTimer=setInterval(()=>scrollTo(curIdx+1<numCards()?curIdx+1:0),5000);
  wrap.addEventListener('mouseenter',()=>clearInterval(autoTimer));
  wrap.addEventListener('mouseleave',()=>{autoTimer=setInterval(()=>scrollTo(curIdx+1<numCards()?curIdx+1:0),5000);});
  track.style.transition='transform .55s cubic-bezier(.25,.46,.45,.94)';
})();


