function openAbout(){
  try{
    const el = document.getElementById('about-page');
    if(el){ el.classList.add('on'); document.body.style.overflow='hidden'; }
    else{ toast('About page not found','err'); }
  }catch(e){ console.error('openAbout error',e); }
}
function closeAbout(){
  try{
    const el = document.getElementById('about-page');
    if(el){ el.classList.remove('on'); document.body.style.overflow=''; }
  }catch(e){}
}
// Close about on overlay click
(function(){
  const el = document.getElementById('about-page');
  if(el) el.addEventListener('click', function(e){
    if(e.target === this) closeAbout();
  });
})();

// ============================================================
// PHASE SWITCHER (navigate between phase dashboards)
// ============================================================
function switchPhase(phase){
  try{
    ['grow','multiply','succeed','legacy'].forEach(p=>{
      const el=document.getElementById('phase-'+p);
      if(el) el.classList.remove('on');
    });
    const target = document.getElementById('phase-'+phase);
    if(target){
      target.classList.add('on');
      document.body.style.overflow='hidden';
      target.scrollTop=0;
      openPhase(phase); // render topics/content
    }
  }catch(e){ console.error('switchPhase error',e); }
}
function closeAllPhases(){
  try{
    ['grow','multiply','succeed','legacy'].forEach(p=>{
      const el=document.getElementById('phase-'+p);
      if(el) el.classList.remove('on');
    });
    document.body.style.overflow='';
    // Scroll back to dashboard
    const dash=document.querySelector('#dash');
    if(dash) dash.scrollIntoView({behavior:'smooth',block:'start'});
  }catch(e){}
}



